import subprocess, tempfile, os, re

def code_verifier(code: str, test_cases: list[dict], timeout: int = 5) -> float:
    """Execute code against test cases. Returns fraction passed (0.0-1.0)."""
    passed = 0
    for tc in test_cases:
        with tempfile.NamedTemporaryFile(suffix='.py', mode='w', delete=False) as f:
            f.write(code)
            path = f.name
        try:
            result = subprocess.run(
                ['python3', path], input=tc['input'],
                capture_output=True, text=True, timeout=timeout,
            )
            if result.stdout.strip() == tc['expected'].strip():
                passed += 1
        except subprocess.TimeoutExpired:
            pass
        finally:
            os.unlink(path)
    return passed / len(test_cases) if test_cases else 0.0


def math_verifier(answer: str, gold: str, tolerance: float = 1e-6) -> float:
    """Numeric comparison with string match fallback."""
    def last_num(s):
        nums = re.findall(r'-?\d+(?:\.\d+)?', s)
        return nums[-1] if nums else None

    pred_num = last_num(answer)
    gold_num  = last_num(gold)

    if pred_num is None or gold_num is None:
        return float(answer.strip() == gold.strip())

    try:
        return float(abs(float(pred_num) - float(gold_num)) < tolerance)
    except ValueError:
        return float(pred_num == gold_num)

from transformers import AutoModelForSequenceClassification, AutoTokenizer
import torch

class OutcomeRewardModel:
    """Lightweight ORM wrapper for Best-of-N selection."""

    def __init__(self, model_id: str):
        self.model = AutoModelForSequenceClassification.from_pretrained(
            model_id, num_labels=1
        )
        self.tokenizer = AutoTokenizer.from_pretrained(model_id)
        self.model.eval()

    @torch.no_grad()
    def score(self, problem: str, response: str) -> float:
        text = f"{problem}\n\n{response}"
        enc  = self.tokenizer(text, return_tensors='pt', truncation=True, max_length=1024)
        return self.model(**enc).logits.squeeze().item()

    def best_of_n(self, problem: str, candidates: list[str]) -> tuple[str, float]:
        scores = [(c, self.score(problem, c)) for c in candidates]
        return max(scores, key=lambda x: x[1])

import re, torch

class ProcessRewardModel:
    """PRM that scores each reasoning step individually."""
    def __init__(self, model, tokenizer):
        self.model     = model
        self.tokenizer = tokenizer

    def split_steps(self, chain: str) -> list[str]:
        steps = re.split(r'(?m)^(?:Step\s+\d+[:.]|\-\s|\d+\.\s)', chain)
        return [s.strip() for s in steps if s.strip()]

    @torch.no_grad()
    def score_chain(self, problem: str, chain: str, aggregation: str = 'min') -> float:
        steps = self.split_steps(chain)
        if not steps:
            return 0.0
        step_scores = []
        prefix = problem + "\n"
        for step in steps:
            prefix += step + "\n"
            enc = self.tokenizer(prefix, return_tensors='pt', truncation=True, max_length=1024)
            score = self.model(**enc).logits.squeeze().sigmoid().item()
            step_scores.append(score)

        if aggregation == 'min':
            return min(step_scores)
        elif aggregation == 'product':
            result = 1.0
            for s in step_scores:
                result *= s
            return result
        return sum(step_scores) / len(step_scores)
